namespace AHS.Common; public static class EnvLoader { public static void Load(string filePath) { if (!File.Exists(filePath)) { Console.WriteLine("⚠️ WARNING: .env file not found at: " + Path.GetFullPath(filePath)); return; } foreach (var line in File.ReadAllLines(filePath)) { if (string.IsNullOrWhiteSpace(line) || line.StartsWith('#')) continue; var parts = line.Split('=', 2, StringSplitOptions.RemoveEmptyEntries); if (parts.Length == 2) { var key = parts[0].Trim(); var value = parts[1].Trim(' ', '\"'); Console.WriteLine($"🔍 DEBUG: Processing key '{key}' from .env"); Environment.SetEnvironmentVariable(key, value); } } } }
